#include <stdio.h>

int main() {
    FILE *f = fopen("poruke.dat", "rb+");
    if (f == NULL) {
        printf("Greska pri otvaranju datoteke.\n");
        return 1;
    }

    char poruka[50];

    printf("Unesite novu poruku: ");
    scanf("%49s", poruka);

    fseek(f, 0, SEEK_SET);
    fwrite(poruka, sizeof(char), 50, f);

    fclose(f);

    printf("Poruka je uspjesno azurirana.\n");

    return 0;
}
